SELECT tenant_name, contact_email
FROM tenants
ORDER BY tenant_name;

SELECT COUNT(*) 
FROM resource_versions 
WHERE created_by = 'specific_user';

SELECT name, description
FROM api_resources
ORDER BY created_date DESC;

SELECT COUNT(DISTINCT port_group_id) AS total_unique_port_groups
FROM port_groups
WHERE tenant_id = 'some_tenant_id';
